import 'package:flutter/material.dart'; import '../../../core/theme/app_theme.dart'; class RemoteNavigationBar extends StatelessWidget { final VoidCallback onBack; final VoidCallback onHome; final VoidCallback onAppSwitch; const RemoteNavigationBar({super.key, required this.onBack, required this.onHome, required this.onAppSwitch}); @override Widget build(BuildContext context) => Container(height: 44, color: Colors.black.withOpacity(0.7), child: Row(mainAxisAlignment: MainAxisAlignment.spaceEvenly, children: [_btn(Icons.arrow_back_ios_new, onBack, 'Back'), _btn(Icons.circle_outlined, onHome, 'Home'), _btn(Icons.square_outlined, onAppSwitch, 'Apps')])); Widget _btn(IconData icon, VoidCallback onTap, String label) => GestureDetector(onTap: onTap, child: Column(mainAxisAlignment: MainAxisAlignment.center, children: [Icon(icon, color: Colors.white, size: 18), Text(label, style: const TextStyle(color: Colors.white54, fontSize: 8))])); }